sql:
SELECT COUNT(DISTINCT c.customer_id) AS total_customers_with_orders
FROM customers c
INNER JOIN orders o ON c.customer_id = o.customer_id;

SELECT AVG(campaign_count) AS average_campaigns_per_customer
FROM (
  SELECT customer_id, COUNT(customer_campaign_id) AS campaign_count
  FROM customer_campaigns
  GROUP BY customer_id
) AS campaign_counts;

SELECT name, loyalty_points
FROM customers
ORDER BY loyalty_points DESC;

external_knowledge:
- Gold rewards are given for 1000 or more loyalty points;
- Silver rewards are given for loyalty points between 500 and 999;
- Bronze rewards are given for loyalty points between 100 and 499.

sql:
SELECT COUNT(DISTINCT o.customer_id) AS number_of_customers
FROM orders o
WHERE o.order_date >= DATETIME('now', '-30 days');

SELECT customer_id, membership_status, AVG(loyalty_points) AS typical_loyalty_points
FROM customers
GROUP BY customer_id, membership_status;

SELECT AVG(total_cost) AS average_total_cost
FROM orders
WHERE order_date >= DATE('now', '-1 month');
